import{B as e,Q as t,s as n,z as r}from"./chunks/framework.GF8LbaeE.js";var i=JSON.parse(`{"title":"Admin","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin.md","filePath":"guide/admin.md"}`),a={name:`guide/admin.md`};function o(n,i,a,o,s,c){return t(),r(`div`,null,[...i[0]||=[e(`<h1 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h1><p>Welcome to the Admin guide. This documentation is automatically generated from the latest game features.</p><h2 id="season-settings-schedule-generation-confirmation" tabindex="-1">Season Settings - Schedule Generation Confirmation <a class="header-anchor" href="#season-settings-schedule-generation-confirmation" aria-label="Permalink to &quot;Season Settings - Schedule Generation Confirmation&quot;">​</a></h2><p>The Season Settings tab showing the &#39;Generate Season Confirmation&#39; button, before execution.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-season-settings-confirmation.png" alt="Season Settings - Schedule Generation Confirmation"></p><hr><h2 id="account-management" tabindex="-1">Account Management <a class="header-anchor" href="#account-management" aria-label="Permalink to &quot;Account Management&quot;">​</a></h2><p>Admins manage all user accounts from this view. Each row shows the account&#39;s username, email address, assigned roles, last login timestamp, and enabled/disabled status. Use Edit to change roles or reset credentials, and Delete to permanently remove an account.</p><p><img src="/all-time-wrestling-rpg/screenshots/account-list-overview.png" alt="Account Management"></p><hr><h2 id="universe-management" tabindex="-1">Universe Management <a class="header-anchor" href="#universe-management" aria-label="Permalink to &quot;Universe Management&quot;">​</a></h2><p>Universes are the top-level containers for all promotion data — shows, wrestlers, titles, factions, and storylines all belong to a universe. An installation can run multiple universes simultaneously, each with its own independent roster, calendar, and championship lineage.</p><p><img src="/all-time-wrestling-rpg/screenshots/universe-list-overview.png" alt="Universe Management"></p><hr><h2 id="export-custom-images" tabindex="-1">Export Custom Images <a class="header-anchor" href="#export-custom-images" aria-label="Permalink to &quot;Export Custom Images&quot;">​</a></h2><p>Download a ZIP of all custom images (wrestlers, factions, titles, arenas, and more) in one click. The archive preserves the original file paths so images can be restored on a new host without reconfiguration.</p><p><img src="/all-time-wrestling-rpg/screenshots/export-universe-images.png" alt="Export Custom Images"></p><hr><h2 id="managing-universe-invites" tabindex="-1">Managing Universe Invites <a class="header-anchor" href="#managing-universe-invites" aria-label="Permalink to &quot;Managing Universe Invites&quot;">​</a></h2><p>Admins can generate invite links to share with prospective members. Targeted links are single-use with a 7-day expiry; Community links are multi-use with no expiry. Active links are listed below with options to revoke.</p><p><img src="/all-time-wrestling-rpg/screenshots/universe-invite-management.png" alt="Managing Universe Invites"></p><hr><h2 id="reviewing-join-requests" tabindex="-1">Reviewing Join Requests <a class="header-anchor" href="#reviewing-join-requests" aria-label="Permalink to &quot;Reviewing Join Requests&quot;">​</a></h2><p>Pending membership requests appear here. Approve to add the user as a member, Reject to decline while allowing them to re-request, or Block to permanently prevent future requests from that account.</p><p><img src="/all-time-wrestling-rpg/screenshots/universe-join-requests.png" alt="Reviewing Join Requests"></p><hr><h2 id="wrestler-relationships-management" tabindex="-1">Wrestler Relationships Management <a class="header-anchor" href="#wrestler-relationships-management" aria-label="Permalink to &quot;Wrestler Relationships Management&quot;">​</a></h2><p>Manage the social fabric of your promotion. Define marriages, family ties, and deep friendships that influence chemistry, AI narration, and random backstage events.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-wrestler-relationships.png" alt="Wrestler Relationships Management"></p><hr><h2 id="generate-template-art" tabindex="-1">Generate Template Art <a class="header-anchor" href="#generate-template-art" aria-label="Permalink to &quot;Generate Template Art&quot;">​</a></h2><p>Create unique branding for your show templates using AI. This art will be used in the booking interface and calendar.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-show-template-art-generation.png" alt="Generate Template Art"></p><hr><h2 id="season-settings-before-schedule-generation" tabindex="-1">Season Settings - Before Schedule Generation <a class="header-anchor" href="#season-settings-before-schedule-generation" aria-label="Permalink to &quot;Season Settings - Before Schedule Generation&quot;">​</a></h2><p>The Season Settings tab showing the &#39;Generate Season Schedule&#39; button, before execution.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-season-settings-before-generation.png" alt="Season Settings - Before Schedule Generation"></p><hr><h2 id="system-performance" tabindex="-1">System Performance <a class="header-anchor" href="#system-performance" aria-label="Permalink to &quot;System Performance&quot;">​</a></h2><p>Monitor AI response times and resource usage.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-observability-performance.png" alt="System Performance"></p><hr><h2 id="season-settings-after-schedule-generation" tabindex="-1">Season Settings - After Schedule Generation <a class="header-anchor" href="#season-settings-after-schedule-generation" aria-label="Permalink to &quot;Season Settings - After Schedule Generation&quot;">​</a></h2><p>The Season Settings tab after successfully generating the season schedule.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-season-settings-after-generation.png" alt="Season Settings - After Schedule Generation"></p><hr><h2 id="cache-management" tabindex="-1">Cache Management <a class="header-anchor" href="#cache-management" aria-label="Permalink to &quot;Cache Management&quot;">​</a></h2><p>Monitor and manage application caches.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-observability-cache.png" alt="Cache Management"></p><hr><h2 id="database-management" tabindex="-1">Database Management <a class="header-anchor" href="#database-management" aria-label="Permalink to &quot;Database Management&quot;">​</a></h2><p>Monitor database statistics and optimize performance.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-observability-database.png" alt="Database Management"></p><hr><h2 id="system-pulse" tabindex="-1">System Pulse <a class="header-anchor" href="#system-pulse" aria-label="Permalink to &quot;System Pulse&quot;">​</a></h2><p>Real-time health status of the application.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-observability-pulse.png" alt="System Pulse"></p><hr><h2 id="admin-tools" tabindex="-1">Admin Tools <a class="header-anchor" href="#admin-tools" aria-label="Permalink to &quot;Admin Tools&quot;">​</a></h2><p>Perform critical maintenance tasks such as manual tier recalculation and account management.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-tools.png" alt="Admin Tools"></p><hr><h2 id="show-templates" tabindex="-1">Show Templates <a class="header-anchor" href="#show-templates" aria-label="Permalink to &quot;Show Templates&quot;">​</a></h2><p>Define reusable templates for your shows. Set up standard segments, match orders, and branding to quickly book consistent weekly episodes or pay-per-views.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-show-templates.png" alt="Show Templates"></p><hr><h2 id="ai-configuration" tabindex="-1">AI Configuration <a class="header-anchor" href="#ai-configuration" aria-label="Permalink to &quot;AI Configuration&quot;">​</a></h2><p>Configure the Artificial Intelligence providers used for match narration, image generation, and creative assistance. You can switch between different LLM providers (OpenAI, Anthropic, Gemini) and configure their specific settings.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-ai-settings.png" alt="AI Configuration"></p><hr><h2 id="injury-management" tabindex="-1">Injury Management <a class="header-anchor" href="#injury-management" aria-label="Permalink to &quot;Injury Management&quot;">​</a></h2><p>Define different types of injuries, their severity, and recovery times. These are used to dynamically affect wrestler performance and availability in the campaign and booking modes.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-injury-types.png" alt="Injury Management"></p><hr><h2 id="wrestler-management" tabindex="-1">Wrestler Management <a class="header-anchor" href="#wrestler-management" aria-label="Permalink to &quot;Wrestler Management&quot;">​</a></h2><p>Manage the entire roster of wrestlers. Add new talent, edit existing stats, assign images, and manage contract details from this centralized view.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-wrestler-list.png" alt="Wrestler Management"></p><hr><h2 id="expansion-management" tabindex="-1">Expansion Management <a class="header-anchor" href="#expansion-management" aria-label="Permalink to &quot;Expansion Management&quot;">​</a></h2><p>Group and toggle themed content sets. Enable or disable entire collections of wrestlers, teams, and factions to customize the available roster for matches and leagues.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-expansion-management.png" alt="Expansion Management"></p><hr><h2 id="video-walkthroughs" tabindex="-1">Video Walkthroughs <a class="header-anchor" href="#video-walkthroughs" aria-label="Permalink to &quot;Video Walkthroughs&quot;">​</a></h2><h3 id="mysql-data-migration-wizard" tabindex="-1">MySQL Data Migration Wizard <a class="header-anchor" href="#mysql-data-migration-wizard" aria-label="Permalink to &quot;MySQL Data Migration Wizard&quot;">​</a></h3><p>Migration complete — all data is now in MySQL and verified. Restart the application with the MySQL Spring profile (spring.profiles.active=mysql) to run in production mode against the new database.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/data-transfer-full-wizard.mp4" type="video/mp4"></video><hr><h3 id="account-management-walkthrough" tabindex="-1">Account Management Walkthrough <a class="header-anchor" href="#account-management-walkthrough" aria-label="Permalink to &quot;Account Management Walkthrough&quot;">​</a></h3><p>New Account dialog — username and email are required; password is set on first login or by the admin. Roles can be combined: a Booker who also plays in leagues needs both the Booker and Player roles.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/account-list-walkthrough.mp4" type="video/mp4"></video><hr><h3 id="universe-management-walkthrough" tabindex="-1">Universe Management Walkthrough <a class="header-anchor" href="#universe-management-walkthrough" aria-label="Permalink to &quot;Universe Management Walkthrough&quot;">​</a></h3><p>Create Universe dialog — name is required; type controls which game rules apply. Standard uses the default ATW ruleset; Fantasy enables league drafts; Historical locks the roster to a specific era.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/universe-list-walkthrough.mp4" type="video/mp4"></video><hr><h3 id="inviting-members-to-a-universe" tabindex="-1">Inviting Members to a Universe <a class="header-anchor" href="#inviting-members-to-a-universe" aria-label="Permalink to &quot;Inviting Members to a Universe&quot;">​</a></h3><p>When someone follows the link and submits a request, click Requests to review it. Approve to add them as a member, Reject to decline, or Block to prevent future requests from that account.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/universe-member-onboarding.mp4" type="video/mp4"></video><hr>`,99)]])}var s=n(a,[[`render`,o]]);export{i as __pageData,s as default};